var e=[{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`오옷! 흥미진진한데?!`,JPN:`おおっ！　面白くなってきたぞ！？`,ENG:`Wow! What's going to happen next?!`,TWN:`哇喔！好像很精彩！`},stage:{bg:`FOREST_NORMAL`,bgm:`THEMA_STREGA`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`이제 좀 이벤트 같네!`,JPN:`ようやくイベントらしくなってきたな！`,ENG:`Now the event gets interesting!`,TWN:`終於有點活動的樣子囉！`},stage:{bg:`FOREST_NORMAL`,bgm:`THEMA_STREGA`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`헉, 헉. 이게 진짜 이벤트로 보이는 건가…….`,JPN:`はあ、はあ。これがイベントに見えるっていうの……`,ENG:`*Huff... Huff...* Do they really think this is still an event...?`,TWN:`哇，這真的看起來像活動嗎……`},stage:{bg:`FOREST_NORMAL`,bgm:`THEMA_STREGA`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`INGRID_STREGA_HALLOWEEN_NULL`,text:{KOREA:`봐 봐! 사람들이 더 몰려 들었어!`,JPN:`見て、見て！　人がもっと集まってきた！`,ENG:`Look! There are more people gathering!`,TWN:`你看！人潮更多咧！`},stage:{bg:`FOREST_NORMAL`,bgm:`THEMA_STREGA`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INGRID_STREGA_HALLOWEEN_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LAURA_STREGA_WEDDING_NULL`,text:{KOREA:`거기 너희들! 수다 떨 시간 있으면 와서 좀 돕지?!`,JPN:`そこの汝ら！　おしゃべりしてる暇があるなら手伝え！`,ENG:`Hey, you two! Why don't you come help instead of chatting?!`,TWN:`你們二個！有時間聊天還不快過來幫幫我？！`},stage:{bg:`FOREST_NORMAL`,bgm:`THEMA_STREGA`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INGRID_STREGA_HALLOWEEN_NULL`,face:`UNIT_SURPRISE`},R:{char_id:`LAURA_STREGA_WEDDING_NULL`,face:`UNIT_HATE`}}}},{id:`L9_1`,type:`dialog`,speaker:`HARAB_QLIPHOTH_WEDDING_FAKE`,text:{KOREA:`아아, 결혼 생활만큼이나 짜릿한 고통을 선사해 드리죠!`,JPN:`ああ、結婚生活のようにうっとりするような苦痛をあげます！`,ENG:`Ahh... You shall experience pain as intoxicating as married life!`,TWN:`啊啊，我就讓你體驗一下如婚姻生活般的痛苦！`},stage:{bg:`FOREST_NORMAL`,bgm:`THEMA_STREGA`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARAB_QLIPHOTH_WEDDING_FAKE`,face:`UNIT_IDLE`},R:{char_id:`LAURA_STREGA_WEDDING_NULL`,face:`UNIT_HATE`}}}},{id:`L10_1`,type:`dialog`,speaker:`LAURA_STREGA_WEDDING_NULL`,text:{KOREA:`얘 점점 눈에 맛이 가고 있다고!`,JPN:`あいつだんだん正気じゃなくなってきてるぞ！`,ENG:`There's no sanity left in her eyes!`,TWN:`她要殺紅眼了！`},stage:{bg:`FOREST_NORMAL`,bgm:`THEMA_STREGA`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARAB_QLIPHOTH_WEDDING_FAKE`,face:`UNIT_IDLE`},R:{char_id:`LAURA_STREGA_WEDDING_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L12_1`,type:`dialog`,speaker:null,text:{KOREA:`이쪽은 곧 끝날 것 같은데…….`,JPN:`こっちはそろそろ終わりそうだけど……`,ENG:`Seems like this part is about to end...`,TWN:`這邊好像快演完咧……`},stage:{bg:`FOREST_NORMAL`,bgm:`THEMA_STREGA`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:null,text:{KOREA:`그럼 저기 저 사람이 최종 보스인가?`,JPN:`するとあそこの人がラスボスかな？`,ENG:`Then, is that person the final boss?`,TWN:`那個人就是最後的大BOSS嗎？`},stage:{bg:`FOREST_NORMAL`,bgm:`THEMA_STREGA`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LAURA_STREGA_WEDDING_NULL`,text:{KOREA:`뭐? 최종 보스?`,JPN:`なに？　ラスボス？`,ENG:`What? Final boss?`,TWN:`什麼？大BOSS？`},stage:{bg:`FOREST_NORMAL`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LAURA_STREGA_WEDDING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`LAURA_STREGA_WEDDING_NULL`,text:{KOREA:`그게 무슨 소리……`,JPN:`いったい何を……`,ENG:`What are they talkin–`,TWN:`什麼意思……`},stage:{bg:`FOREST_NORMAL`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LAURA_STREGA_WEDDING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`LAURA_STREGA_WEDDING_NULL`,text:{KOREA:` ?!`,JPN:` ！？`,ENG:`?!`,TWN:` ？！`},stage:{bg:`FOREST_NORMAL`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LAURA_STREGA_WEDDING_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CATHY_CIVIL_NULL_NULL`,text:{KOREA:`공기의 흐름이… 바뀌었어……?`,JPN:`空気の流れが……変わった……？`,ENG:`The atmosphere... It changed...?`,TWN:`氣氛好像……不太對……？`},stage:{bg:`FOREST_NORMAL`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CATHY_CIVIL_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};